function readJsonIfPresent(filePath) {
  if (!filePath || !fs.existsSync(filePath)) {
    return null;
  }
  return JSON.parse(fs.readFileSync(filePath, 'utf8'));
}

function listFilesIfPresent(dirPath) {
  if (!dirPath || !fs.existsSync(dirPath)) {
    return [];
  }
  return fs.readdirSync(dirPath, { withFileTypes: true })
    .filter((entry) => entry.isFile())
    .map((entry) => path.join(dirPath, entry.name))
    .sort((left, right) => left.localeCompare(right));
}

function toBigIntOrNull(value) {
  if (value === null || value === undefined || value === '') {
    return null;
  }
  try {
    return BigInt(String(value).replace(/,/g, ''));
  } catch {
    return null;
  }
}

function formatInteger(value) {
  if (value === null || value === undefined) {
    return null;
  }
  return String(value).replace(/\B(?=(\d{3})+(?!\d))/g, ',');
}

function decimalPercentLabel(part, total, decimals = 6) {
  const numerator = toBigIntOrNull(part);
  const denominator = toBigIntOrNull(total);
  if (numerator === null || denominator === null || denominator === 0n) {
    return null;
  }
  const scale = 10n ** BigInt(decimals);
  const scaled = (numerator * 100n * scale) / denominator;
  if (scaled === 0n && numerator > 0n) {
    return `<0.${'0'.repeat(Math.max(0, decimals - 1))}1%`;
  }
  const whole = scaled / scale;
  const fraction = String(scaled % scale).padStart(decimals, '0');
  return `${whole}.${fraction}%`;
}

function decimalPercentNumber(part, total) {
  const numerator = toBigIntOrNull(part);
  const denominator = toBigIntOrNull(total);
  if (
    numerator === null ||
    denominator === null ||
    denominator === 0n ||
    numerator > BigInt(Number.MAX_SAFE_INTEGER) ||
    denominator > BigInt(Number.MAX_SAFE_INTEGER)
  ) {
    return null;
  }
  return Number(((Number(numerator) / Number(denominator)) * 100).toFixed(6));
}

function countMetric(value) {
  const integer = toBigIntOrNull(value);
  if (integer === null) {
    return {
      value: value ?? null,
      label: value === null || value === undefined ? null : String(value),
    };
  }
  return {
    value: integer.toString(),
    label: formatInteger(integer.toString()),
  };
}

function ratioMetric(part, total, decimals = 6) {
  const numerator = toBigIntOrNull(part);
  const denominator = toBigIntOrNull(total);
  return {
    part: numerator === null ? null : countMetric(numerator).value,
    partLabel: numerator === null ? null : countMetric(numerator).label,
    total: denominator === null ? null : countMetric(denominator).value,
    totalLabel: denominator === null ? null : countMetric(denominator).label,
    percent: decimalPercentNumber(numerator, denominator),
    percentLabel: decimalPercentLabel(numerator, denominator, decimals),
  };
}

function isDoneStatus(status) {
  return /^(done|complete|completed|closed|passed|verified|discharged)$/i.test(String(status ?? ''));
}

function isInProgressStatus(status) {
  return /^(in_progress|running|active|current)$/i.test(String(status ?? ''));
}

function summarizeTaskBoard(taskList) {
  const currentTasks = Array.isArray(taskList?.currentTasks) ? taskList.currentTasks : [];
  const completedAnchors = Array.isArray(taskList?.completedAnchors) ? taskList.completedAnchors : [];
  const nextNeededSteps = Array.isArray(taskList?.nextNeededSteps) ? taskList.nextNeededSteps : [];
  const primaryAgentAction = taskList?.agentFlow?.primaryNextAction ?? null;
  const completedAnchorCount = completedAnchors.filter((item) => isDoneStatus(item.status)).length;
  const currentDoneCount = currentTasks.filter((task) => isDoneStatus(task.status)).length;
  const currentInProgressCount = currentTasks.filter((task) => isInProgressStatus(task.status)).length;
  const currentOpenCount = currentTasks.length - currentDoneCount - currentInProgressCount;
  const rollingDoneCount = completedAnchorCount + currentDoneCount;
  const rollingTotalCount = completedAnchors.length + currentTasks.length;

  return {
    meaning: 'Rolling task-board progress over currently named completed anchors plus currently named tasks. This is work tracking, not probability of proof.',
    rollingKnownWork: {
      doneCount: rollingDoneCount,
      totalCount: rollingTotalCount,
      openOrActiveCount: Math.max(0, rollingTotalCount - rollingDoneCount),
      percent: ratioMetric(rollingDoneCount, rollingTotalCount, 2),
    },
    currentLoop: {
      doneCount: currentDoneCount,
      inProgressCount: currentInProgressCount,
      openCount: currentOpenCount,
      totalCount: currentTasks.length,
      percent: ratioMetric(currentDoneCount, currentTasks.length, 2),
    },
    completedAnchors: {
      doneCount: completedAnchorCount,
      totalCount: completedAnchors.length,
    },
    nextNeededStepCount: nextNeededSteps.length,
    primaryAgentAction,
    activeTask: currentTasks.find((task) => isInProgressStatus(task.status)) ?? null,
    primaryNextNeededStep: nextNeededSteps[0] ?? null,
  };
}

function summarizeExactLane(taskList) {
  const strategy = taskList?.finiteGapStrategy ?? null;
  const threshold = toBigIntOrNull(strategy?.operationalThreshold?.integer);
  const publicRawExactMax = toBigIntOrNull(strategy?.publicRepoRawExactMax ?? strategy?.exactMax);
  const localRolloutMax = toBigIntOrNull(strategy?.localIgnoredRolloutMax);

  if (!strategy || threshold === null) {
    return {
      status: 'not_available',
      meaning: 'No finite threshold denominator is recorded for this problem yet.',
    };
  }

  const publicRemaining = publicRawExactMax === null ? null : threshold - publicRawExactMax;
  const localRemaining = localRolloutMax === null ? null : threshold - localRolloutMax;

  return {
    status: strategy.status ?? 'available',
    meaning: 'Exact row coverage against the recorded operational threshold. This is a brute-force lane measure, not the preferred all-N proof measure.',
    verdict: strategy.verdict ?? null,
    recommendedMode: strategy.recommendedMode ?? null,
    operationalThreshold: {
      raw: strategy.operationalThreshold?.raw ?? null,
      trustStatus: strategy.operationalThreshold?.trustStatus ?? null,
      source: strategy.operationalThreshold?.source ?? null,
      rows: countMetric(threshold),
    },
    publicRawExact: {
      interval: strategy.publicRepoRawExactInterval ?? strategy.latestVerifiedInterval ?? null,
      coveredRows: countMetric(publicRawExactMax),
      remainingRows: countMetric(publicRemaining),
      coveredPercent: ratioMetric(publicRawExactMax, threshold, 15),
    },
    localRolloutEvidence: {
      interval: strategy.localIgnoredRolloutInterval ?? null,
      sourceStatus: strategy.endpointCertificate?.sourceStatus ?? null,
      committedAsRawClaim: strategy.raw40500PacketCommitted ?? false,
      coveredRows: countMetric(localRolloutMax),
      remainingRows: countMetric(localRemaining),
      coveredPercent: ratioMetric(localRolloutMax, threshold, 15),
    },
    projectedEndpointChecksToThreshold: countMetric(strategy.projectedEndpointChecksToOperationalThreshold),
    guidance: Array.isArray(strategy.guidance) ? strategy.guidance : [],
  };
}

function summarizeConvergencePacket(convergencePacket) {
  if (!convergencePacket) {
    return {
      status: 'missing',
      meaning: 'No convergence assembly packet is present yet.',
    };
  }

  const assembledPieces = Array.isArray(convergencePacket.assembledPieces)
    ? convergencePacket.assembledPieces
    : [];
  const certifiedBulletCount = assembledPieces.reduce((count, piece) => {
    const bullets = Array.isArray(piece.provedOrCertified) ? piece.provedOrCertified.length : 0;
    return count + bullets;
  }, 0);
  const finiteMeasure = convergencePacket.finiteMeasureOrNoMeasureYet ?? {};
  const localMeasure = finiteMeasure.localEndpointMeasure ?? null;
  const primaryCompression = convergencePacket.compressionCandidateLemma?.primary ?? null;

  return {
    status: convergencePacket.status ?? 'present',
    meaning: 'Convergence assembly says what the current pieces support and what is still missing before a global close.',
    assembledPieceCount: assembledPieces.length,
    certifiedBulletCount,
    supportedClaim: convergencePacket.supportedClaim ?? null,
    globalMeasureStatus: finiteMeasure.global282FirstFailureMeasure ?? 'unknown',
    localEndpointMeasure: localMeasure,
    compressionCandidate: primaryCompression
      ? {
          id: primaryCompression.id ?? null,
          statement: primaryCompression.statement ?? null,
          missingForUse: primaryCompression.missingForUse ?? null,
        }
      : null,
    remainingPuzzleBoundary: convergencePacket.remainingPuzzleBoundary ?? null,
    oneNextAction: convergencePacket.oneNextAction ?? null,
    oneVerificationCommand: convergencePacket.oneVerificationCommand ?? null,
  };
}

function readJsonFileSummary(filePath, packProblemDir) {
  const doc = readJsonIfPresent(filePath);
  if (!doc) {
    return null;
  }
  const stat = fs.statSync(filePath);
  return {
    path: filePath,
    relativePath: path.relative(packProblemDir, filePath),
    generatedAt: doc.generatedAt ?? null,
    mtimeMs: stat.mtimeMs,
    doc,
  };
}

function sortJsonSummariesNewestFirst(left, right) {
  const leftTime = Date.parse(left.generatedAt ?? '') || left.mtimeMs;
  const rightTime = Date.parse(right.generatedAt ?? '') || right.mtimeMs;
  return rightTime - leftTime;
}

function summarizeAvailabilitySplit(fileSummary) {
  if (!fileSummary?.doc?.availabilitySplit) {
    return null;
  }
  const split = fileSummary.doc.availabilitySplit;
  const target = fileSummary.doc.target ?? {};
  const available = toBigIntOrNull(split.availableResidueCount);
  const unavailable = toBigIntOrNull(split.unavailableResidueCount);
  const partitionTotal = available !== null && unavailable !== null ? available + unavailable : null;
  const period = toBigIntOrNull(split.period ?? target.endpointPrimeSquare);
  const firstChild = fileSummary.doc.firstAvailableSquareObstruction ?? null;

  return {
    status: fileSummary.doc.status ?? 'present',
    path: fileSummary.path,
    relativePath: fileSummary.relativePath,
    generatedAt: fileSummary.generatedAt,
    targetDescription: target.description ?? null,
    endpointPrime: target.endpointPrime ?? firstChild?.endpointPrime ?? null,
    endpointPrimeSquare: countMetric(target.endpointPrimeSquare ?? period),
    kFormulaInParameter: split.kFormulaInParameter ?? null,
    partition: {
      period: countMetric(period),
      availableResidues: countMetric(available),
      unavailableResidues: countMetric(unavailable),
      partitionedResidues: countMetric(partitionTotal),
      partitionCoverage: ratioMetric(partitionTotal, period, 6),
      availableResiduePercent: ratioMetric(available, period ?? partitionTotal, 6),
      unavailableResiduePercent: ratioMetric(unavailable, period ?? partitionTotal, 6),
    },
    emittedChild: firstChild
      ? {
          label: `${target.endpointPrime ?? firstChild.endpointPrime}/q${firstChild.obstructionPrime}`,
          obstructionPrime: firstChild.obstructionPrime ?? null,
          obstructionSquare: firstChild.obstructionSquare ?? null,
          tCongruence: firstChild.tCongruence?.expression ?? null,
        }
      : null,
    closure: {
      status: 'open',
      percentComplete: null,
      reason: 'The split is measured, but its emitted child and unavailable complement are not a closed finite proof tree yet.',
    },
  };
}

