function summarizeFactorizationBlocker(fileSummary) {
  if (!fileSummary?.doc || !String(fileSummary.relativePath).includes('factorization_blocker_open_leaf')) {
    return null;
  }
  const doc = fileSummary.doc;
  return {
    status: doc.status ?? 'present',
    path: fileSummary.path,
    relativePath: fileSummary.relativePath,
    generatedAt: fileSummary.generatedAt,
    activeAtom: doc.activeAtom ?? null,
    sourceBoundaryPacket: doc.sourceBoundaryPacket ?? null,
    leaf: doc.leaf ?? null,
    candidateCount: Array.isArray(doc.candidateBoundaries) ? doc.candidateBoundaries.length : 0,
    candidateEndpointPrimes: Array.isArray(doc.candidateBoundaries)
      ? doc.candidateBoundaries.map((candidate) => candidate.endpointPrime).filter(Boolean)
      : [],
    proofBoundary: doc.proofBoundary ?? null,
    recommendedNextAction: doc.recommendedNextAction ?? null,
    claims: doc.claims ?? null,
  };
}

function summarizeFactorizationBoundary(fileSummary) {
  if (!fileSummary?.doc || !String(fileSummary.relativePath).includes('factorization_boundary')) {
    return null;
  }
  const doc = fileSummary.doc;
  const candidates = Array.isArray(doc.trialRepairCandidates)
    ? doc.trialRepairCandidates.map((candidate) => ({
        endpointPrime: candidate.endpointPrime ?? null,
        k: candidate.k ?? null,
        delta: candidate.delta ?? null,
        withinWindow: candidate.withinWindow ?? null,
        exactCertificateStatus: candidate.exactCertificateStatus ?? null,
        cofactorDigits: candidate.partialFactorization?.cofactorDigits ?? null,
        boundedEcmFactorFound: candidate.boundedEcmStatus?.factorFound ?? null,
        boundedAttemptCount: Array.isArray(candidate.boundedEcmStatus?.rungs)
          ? candidate.boundedEcmStatus.rungs.length
          : 0,
        latestBoundedAttemptStatus: Array.isArray(candidate.boundedEcmStatus?.rungs)
          ? candidate.boundedEcmStatus.rungs.at(-1)?.status ?? null
          : null,
      }))
    : [];
  return {
    status: doc.status ?? 'present',
    path: fileSummary.path,
    relativePath: fileSummary.relativePath,
    generatedAt: fileSummary.generatedAt,
    targetDescription: doc.target?.description ?? null,
    activeAtom: doc.activeAtom ?? null,
    boundedScan: {
      endpointPrimeRange: doc.boundedScan?.endpointPrimeRange ?? null,
      trialSquarePrimeLimit: doc.boundedScan?.trialSquarePrimeLimit ?? null,
      withinWindowEndpointCount: doc.boundedScan?.withinWindowEndpointCount ?? null,
      trialSquarefreeWithinWindowCandidates: doc.boundedScan?.trialSquarefreeWithinWindowCandidates ?? [],
      easyCertificateFound: doc.boundedScan?.easyCertificateFound ?? null,
    },
    candidateCount: candidates.length,
    candidates,
    proofBoundary: doc.proofBoundary ?? null,
    recommendedNextAction: doc.recommendedNextAction ?? null,
    claims: doc.claims ?? null,
  };
}

